const invoiceUrl = $.input.invoiceUrl || '';
const invoiceText = $.input.invoiceText || '';
return { hasUrl: invoiceUrl.length > 0, invoiceUrl: invoiceUrl, invoiceText: invoiceText, source: invoiceUrl ? 'url' : 'text' };

const info = $.steps.getInvoiceContent.output;
let content = '';
if (info.hasUrl) {
  const resp = $.steps.scrapeInvoice.response?.data || $.steps.scrapeInvoice.response || {};
  content = resp.markdown || resp.content || resp.text || '';
}
if (!content) content = info.invoiceText || '';
return { content: content.slice(0, 10000), source: info.source };

const content = $.steps.prepareContent.output.content;

let prompt = 'You are an invoice processing specialist with OCR and data extraction expertise. Extract all structured data from the following invoice.

';
prompt += 'INVOICE CONTENT:
' + content + '

';
prompt += 'INSTRUCTIONS:
';
prompt += '- Extract all invoice header info (vendor, date, number, due date)
';
prompt += '- Extract all line items with quantities, unit prices, and totals
';
prompt += '- Calculate subtotals, tax, and grand total
';
prompt += '- Identify payment terms and methods
';
prompt += '- Flag any discrepancies or unusual items

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "vendor": { "name": "", "address": "", "email": "", "phone": "" },
';
prompt += '  "invoiceNumber": "",
';
prompt += '  "invoiceDate": "",
';
prompt += '  "dueDate": "",
';
prompt += '  "currency": "USD",
';
prompt += '  "lineItems": [{ "description": "", "quantity": 0, "unitPrice": 0, "total": 0 }],
';
prompt += '  "subtotal": 0,
';
prompt += '  "tax": 0,
';
prompt += '  "grandTotal": 0,
';
prompt += '  "paymentTerms": "",
';
prompt += '  "notes": "",
';
prompt += '  "flags": [],
';
prompt += '  "confidence": "high|medium|low"
';
prompt += '}';
return { prompt };

let raw = $.steps.aiExtraction.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { vendor: { name: 'Unknown' }, invoiceNumber: '', invoiceDate: '', dueDate: '', currency: 'USD', lineItems: [], subtotal: 0, tax: 0, grandTotal: 0, paymentTerms: '', notes: raw.slice(0, 300), flags: [], confidence: 'low' }; }

const ai = $.steps.parseAI.output;
const headerRow = [
  ai.invoiceNumber || '',
  ai.invoiceDate || '',
  ai.dueDate || '',
  ai.vendor?.name || '',
  ai.vendor?.email || '',
  String(ai.grandTotal || 0),
  ai.currency || 'USD',
  String(ai.tax || 0),
  ai.paymentTerms || '',
  ai.confidence || ''
];

const lineRows = [];
const items = ai.lineItems || [];
items.forEach(function(item) {
  lineRows.push([
    ai.invoiceNumber || '',
    item.description || '',
    String(item.quantity || 0),
    String(item.unitPrice || 0),
    String(item.total || 0)
  ]);
});

return { headerRow: [headerRow], lineRows: lineRows };

const ai = $.steps.parseAI.output;
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Invoice Processed', emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Invoice #:*\n' + (ai.invoiceNumber || 'N/A') },
  { type: 'mrkdwn', text: '*Vendor:*\n' + (ai.vendor?.name || 'Unknown') }
] });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Date:*\n' + (ai.invoiceDate || 'N/A') },
  { type: 'mrkdwn', text: '*Due:*\n' + (ai.dueDate || 'N/A') }
] });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Grand Total:*\n' + (ai.currency || '$') + ' ' + (ai.grandTotal || 0) },
  { type: 'mrkdwn', text: '*Confidence:*\n' + (ai.confidence || 'N/A') }
] });
blocks.push({ type: 'divider' });

const items = ai.lineItems || [];
if (items.length > 0) {
  let itemText = '*Line Items:*\n';
  items.slice(0, 8).forEach(function(item) {
    itemText += '- ' + (item.description || 'Item') + ' x' + (item.quantity || 1) + ' = ' + (ai.currency || '$') + (item.total || 0) + '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: itemText.slice(0, 1800) } });
}

if (ai.flags && ai.flags.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':warning: *Flags:* ' + ai.flags.join(', ') } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Saved to Google Sheets | Powered by Claude AI OCR' }] });
const fallbackText = 'Invoice ' + (ai.invoiceNumber || 'N/A') + ' from ' + (ai.vendor?.name || 'Unknown') + ': ' + (ai.currency || '$') + (ai.grandTotal || 0);
return { blocks, fallbackText };
